pub enum UdtStatus {
    Init,
    Opened,
    Listening,
    Connecting,
    Connected,
    Broken,
    Closing,
    Closed,
}

impl UdtStatus {
    pub(crate) fn is_alive(&self) -> bool {
        *self != UdtStatus::Broken && *self != UdtStatus::Closing && *self != UdtStatus::Closed
    }
}

